content.query:
let filled = customEvents | where timestamp {TimeRange} | where name == 'CCL.AutoFill.Completed' | extend matterId = tostring(customDimensions.matterId) | project matterId, filledAt = timestamp;
let tested = customEvents | where timestamp {TimeRange} | where name == 'CCL.PressureTest.Completed' | extend matterId = tostring(customDimensions.matterId) | project matterId, testedAt = timestamp;
let approved = customEvents | where timestamp {TimeRange} | where name == 'CCL.Approve.Completed' | extend matterId = tostring(customDimensions.matterId) | project matterId, approvedAt = timestamp;
filled
| join kind=leftouter tested on matterId
| join kind=leftouter approved on matterId
| extend fillToTestMin = datetime_diff('minute', testedAt, filledAt)
| extend testToApproveMin = datetime_diff('minute', approvedAt, testedAt)
| project matterId, filledAt, testedAt, approvedAt, fillToTestMin, testToApproveMin
| order by filledAt desc
